sql:
SELECT mean_rate, sample_size
FROM infection_rates
WHERE seasonal_period = 'winter';

SELECT age_group_id, AVG(mean_rate) AS average_infection_rate
FROM infection_rates
GROUP BY age_group_id;

SELECT vaccine_strain, COUNT(subtype_id) as subtype_count
FROM influenza_subtypes
GROUP BY vaccine_strain;

SELECT subtype_name, transmission_rate, mortality_rate
FROM influenza_subtypes
WHERE vaccine_strain = 'Yes';

SELECT AVG(mortality_rate) AS average_mortality_rate
FROM influenza_subtypes
WHERE vaccine_strain = 'Yes';

SELECT mean_rate, sample_size
FROM infection_rates
WHERE rate_id = 1;

SELECT subtype_name
FROM influenza_subtypes
WHERE transmission_rate = (SELECT MAX(transmission_rate) FROM influenza_subtypes);

SELECT subtype_name, transmission_rate
FROM influenza_subtypes
ORDER BY transmission_rate DESC;

SELECT subtype_name
FROM influenza_subtypes
WHERE transmission_rate > (SELECT AVG(transmission_rate) FROM influenza_subtypes);

SELECT subtype_name, transmission_rate, mortality_rate
FROM influenza_subtypes
ORDER BY transmission_rate DESC;

external_knowledge:
; The 'Winter' season is the period typically associated with the highest influenza infection rates in many regions; 
; 'Mixed' vaccination status implies that the study population includes both vaccinated and unvaccinated individuals; 
; Infection rate per 100,000 population is a common metric used in epidemiology to compare disease incidence across different populations.
